   420→std::unique_ptr<CommonDurationFormatter>
   421→CommonDurationFormatter::create(absl::string_view sub_command) {
   422→  // Split the sub_command by ':'.
   423→  absl::InlinedVector<absl::string_view, 3> parsed_sub_commands = absl::StrSplit(sub_command, ':');
   424→
   425→  if (parsed_sub_commands.size() < 2 || parsed_sub_commands.size() > 3) {
   426→    throwEnvoyExceptionOrPanic(
   427→        fmt::format("Invalid common duration configuration: {}.", sub_command));
   428→  }
   429→
   430→  absl::string_view start = parsed_sub_commands[0];
   431→  absl::string_view end = parsed_sub_commands[1];
   432→
   433→  // Milliseconds is the default precision.
   434→  DurationPrecision precision = DurationPrecision::Milliseconds;
   435→
   436→  if (parsed_sub_commands.size() == 3) {
   437→    absl::string_view precision_str = parsed_sub_commands[2];
   438→    if (precision_str == MillisecondsPrecision) {
   439→      precision = DurationPrecision::Milliseconds;
   440→    } else if (precision_str == MicrosecondsPrecision) {
   441→      precision = DurationPrecision::Microseconds;
   442→    } else if (precision_str == NanosecondsPrecision) {
   443→      precision = DurationPrecision::Nanoseconds;
   444→    } else {
   445→      throwEnvoyExceptionOrPanic(
   446→          fmt::format("Invalid common duration precision: {}.", precision_str));
   447→    }
   448→  }
   449→
   450→  TimePointGetter start_getter = getTimePointGetterByName(start);
   451→  TimePointGetter end_getter = getTimePointGetterByName(end);
   452→
   453→  return std::make_unique<CommonDurationFormatter>(std::move(start_getter), std::move(end_getter),
   454→                                                   precision);
   455→}
