   457→absl::optional<uint64_t>
   458→CommonDurationFormatter::getDurationCount(const StreamInfo::StreamInfo& info) const {
   459→  auto time_point_beg = time_point_beg_(info);
   460→  auto time_point_end = time_point_end_(info);
   461→
   462→  if (!time_point_beg.has_value() || !time_point_end.has_value()) {
   463→    return absl::nullopt;
   464→  }
   465→
   466→  if (time_point_end.value() < time_point_beg.value()) {
   467→    return absl::nullopt;
   468→  }
   469→
   470→  auto duration = time_point_end.value() - time_point_beg.value();
   471→
   472→  switch (duration_precision_) {
   473→  case DurationPrecision::Milliseconds:
   474→    return std::chrono::duration_cast<std::chrono::milliseconds>(duration).count();
   475→  case DurationPrecision::Microseconds:
   476→    return std::chrono::duration_cast<std::chrono::microseconds>(duration).count();
   477→  case DurationPrecision::Nanoseconds:
   478→    return std::chrono::duration_cast<std::chrono::nanoseconds>(duration).count();
   479→  }
   480→  PANIC("Invalid duration precision");
   481→}
